    "durationSec": 6.176,
    "durationFrames": 185,
    "speaker": "ずんだもん",
    "text": "3つ目。大切なのは「何と呼ぶか」ではなく「何ができるか」なのだ。",
    "speakerColor": "#22c55e",
    "sceneId": 11,
    "sceneTitle": "本当に大切なこと",
    "audioFile": "audio/css_programming_language/scene_11_03.wav"
